+  diag_msg = smoother_->terminationTypeToDiagnosticStatus(termination_type, diagnostic_warning_status,
+                                                          diagnostic_error_status);
+  EXPECT_EQ(diag_msg.level, diagnostic_msgs::DiagnosticStatus::ERROR);
+}
